document.addEventListener("DOMContentLoaded",function(){"use strict";var e=document.getElementById("principal"),t=document.getElementById("rate"),n=document.getElementById("years"),d=document.getElementById("monthly"),r=document.getElementById("calc-btn"),o=document.getElementById("reset-btn"),l=document.getElementById("result"),a=document.getElementById("table-container"),i=document.getElementById("yearly-tbody"),u=document.getElementById("result-total"),c=document.getElementById("result-invested"),m=document.getElementById("result-profit"),s=document.getElementById("result-return-rate");function g(e){return Math.round(e).toLocaleString()+"円"}r.addEventListener("click",function(){var r=parseFloat(e.value)||0,o=parseFloat(t.value),p=parseInt(n.value,10),v=parseFloat(d.value)||0;if(isNaN(o)||o<0)alert("年利率を正しく入力してください。");else if(isNaN(p)||p<1||p>100)alert("運用期間を1〜100年で入力してください。");else if(r<=0&&v<=0)alert("元本または毎月の積立額を入力してください。");else{var y=o/100/12;i.innerHTML="";for(var x=r,b=r,E=1;E<=p;E++){for(var I=0;I<12;I++)x=x*(1+y)+v;var h=x-(b=r+12*v*E),B=document.createElement("tr");B.innerHTML='<td style="padding: 6px 8px; text-align: right; border-bottom: 1px solid var(--color-border);">'+E+'年目</td><td style="padding: 6px 8px; text-align: right; border-bottom: 1px solid var(--color-border);">'+g(b)+'</td><td style="padding: 6px 8px; text-align: right; border-bottom: 1px solid var(--color-border);">'+g(h)+'</td><td style="padding: 6px 8px; text-align: right; border-bottom: 1px solid var(--color-border);">'+g(x)+"</td>",i.appendChild(B)}var f=r+12*v*p,L=x-f,C=f>0?L/f*100:0;u.textContent=g(x),c.textContent=g(f),m.textContent=g(L),s.textContent=C.toFixed(1)+"%",l.hidden=!1,a.hidden=!1,l.scrollIntoView({behavior:"smooth"})}}),o.addEventListener("click",function(){e.value="",t.value="",n.value="",d.value="0",l.hidden=!0,a.hidden=!0,i.innerHTML=""})});